 * soundex algorithm, but better at finding similar sounding words.
 * All input is converted to upper case.
 * Limitations: Input format is expected to be a single ASCII word
 * with only characters in the A - Z range, no punctuation or numbers.
 *
 * @param txt String to find the metaphone code for
 * @return A metaphone code corresponding to the String supplied
 */
public String metaphone(final String txt) {
    boolean hard = false;
    final int txtLength;
    if (txt == null || (txtLength = txt.length()) == 0) {
        return "";
    }
    // single character is itself
    if (txtLength == 1) {
        return txt.toUpperCase(java.util.Locale.ENGLISH);
    }

    final char[] inwd = txt.toUpperCase(java.util.Locale.ENGLISH).toCharArray();

    final StringBuilder local = new StringBuilder(40); // manipulate
    final StringBuilder code = new StringBuilder(10); // output
    // handle initial 2 characters exceptions
    switch (inwd[0]) {
    case 'K':
    case 'G':
    case 'P': /* looking for KN, etc */
        if (inwd[1] == 'N') {
            local.append(inwd, 1, inwd.length - 1);
        } else {
            local.append(inwd);
        }
        break;
    case 'A': /* looking for AE */
        if (inwd[1] == 'E') {
            local.append(inwd, 1, inwd.length - 1);
        } else {
            local.append(inwd);
        }
        break;
    case 'W': /* looking for WR or WH */
        if (inwd[1] == 'R') { // WR -> R
            local.append(inwd, 1, inwd.length - 1);
            break;
        }
        if (inwd[1] == 'H') {
            local.append(inwd, 1, inwd.length - 1);
            local.setCharAt(0, 'W'); // WH -> W
        } else {
            local.append(inwd);
        }
        break;
    case 'X': /* initial X becomes S */
        inwd[0] = 'S';
        local.append(inwd);
        break;
    default:
        local.append(inwd);
    } // now local has working string with initials fixed

    final int wdsz = local.length();
    int n = 0;

    while (code.length() < this.getMaxCodeLen() && n < wdsz) { // max code size of 4 works well
        final char symb = local.charAt(n);
        // remove duplicate letters except C
        if (symb != 'C' && isPreviousChar(local, n, symb)) {
            n++;
        } else { // not dup
            switch (symb) {
            case 'A':
            case 'E':
            case 'I':
            case 'O':
            case 'U':
                if (n == 0) {
                    code.append(symb);
                }
                break; // only use vowel if leading char
            case 'B':
