                    break;
                }
                code.append(symb);
                break;
            case 'C': // lots of C special cases
                /* discard if SCI, SCE or SCY */
                if (isPreviousChar(local, n, 'S') && !isLastChar(wdsz, n) && FRONTV.indexOf(local.charAt(n + 1)) >= 0) {
                    break;
                }
                if (regionMatch(local, n, "CIA")) { // "CIA" -> X
                    code.append('X');
                    break;
                }
