                    break; // terminal H
                }
                if (n > 0 && VARSON.indexOf(local.charAt(n - 1)) >= 0) {
                    break;
                }
                if (isVowel(local, n + 1)) {
                    code.append('H'); // Hvowel
                }
                break;
            case 'F':
            case 'J':
            case 'L':
            case 'M':
            case 'N':
            case 'R':
                code.append(symb);
                break;
            case 'K':
                if (n > 0) { // not initial
                    if (!isPreviousChar(local, n, 'C')) {
