                if ((n == 0 || isVowel(inwd, n - 1)) && isVowel(inwd, n + 1)) {
                    metaph.append('h');
                }
                break;
            case 'j':
                metaph.append('j');
                break;
            case 'k':
                if (n > 0 && inwd.charAt(n - 1) != 'c') {
                    metaph.append('k');
                }
                break;
            case 'l':
                metaph.append('l');
                break;
            case 'm':
                metaph.append('m');
                break;
            case 'n':
                metaph.append('n');
                break;
            case 'p':
                if (!isLastChar(wdsz, n) && inwd.charAt(n + 1) == 'h') {
                    metaph.append('f');
                    n++;
                } else {
                    metaph.append('p');
                }
                break;
            case 'q':
                metaph.append('k');
                break;
            case 'r':
                metaph.append('r');
                break;
            case 's':
                if (regionMatch(inwd, n, "sh")) {
                    metaph.append('x');
                    n++;
                } else {
                    metaph.append('s');
                }
                break;
            case 't':
                if (regionMatch(inwd, n, "th")) {
                    metaph.append('0');
                    n++;
                } else if (regionMatch(inwd, n, "tch")) {
                    metaph.append('x');
                    n += 2;
                } else {
                    metaph.append('t');
                }
                break;
            case 'v':
                metaph.append('f');
                break;
            case 'w':
                if (n == 0 && isVowel(inwd, n + 1)) {
                    metaph.append('w');
                } else if (!isLastChar(wdsz, n) && inwd.charAt(n + 1) == 'h') {
                    metaph.append('w');
                    n++;
                }
                break;
            case 'x':
                metaph.append('ks');
                break;
            case 'y':
                if (isVowel(inwd, n + 1)) {
                    metaph.append('y');
                }
                break;
            case 'z':
                metaph.append('s');
                break;
            default:
                break;
        }
        n++;
    }

    return metaph.toString().toUpperCase();
}
